import React from 'react'


class Converter extends React.Component{
    constructor(props){
        super(props)
        this.state = {
            firstCur: "USD",
            secCur: "USD",
            firstVal: 1,
            secVal: 1,
            values: {}
        }

        this.handleChange = this.handleChange.bind(this);
        this.componentDidMount = this.componentDidMount.bind(this);
        this.componentDidUpdate = this.componentDidUpdate.bind(this);
    }

    codeName = {
        'USD': 'Доллар', 'EUR': 'Евро', 'CAD': 'Канадский доллар', 
        'HKD': 'Гонконгский доллар', 'ISK': 'Исландская крона', 
        'PHP': 'Филиппинское песо', 'DKK': 'Датская крона', 'HUF': 'Венгерский форинт', 
        'CZK': 'Чешская крона', 'GBP': 'Фунт стерлинга', 'RON': 'Румынские лей', 
        'SEK': 'Шведская крона', 'IDR': 'Индонезийская рупия', 
        'INR': 'Индийская рупия', 'BRL': 'Бразильский реал', 'RUB': 'Рубль', 
        'HRK': 'Хорватская куна', 'JPY': 'Японская иена', 'THB': 'Тайский бат', 
        'CHF': 'Швейцарский франк', 'MYR': 'Малайзийский ринггит', 'BGN': 'Болгарский лев', 
        'TRY': 'Турецкая лира', 'CNY': 'Китайский юань', 'NOK': 'Норвежская крона', 
        'NZD': 'Новозеландский доллар', 'ZAR': 'Южноафриканский ранд', 
        'MXN': 'Мексиканское песо', 'SGD': 'Сингапурский доллар', 
        'AUD': 'Австралийский доллар', 'ILS': 'Израильские шекели', 
        'KRW': 'Юэнокорейская вона', 'PLN': 'Польский злотый'
    }

    componentDidMount(){
        console.log(this.state.values)
        this.callApi(this.state.firstCur);
    }

    componentDidUpdate(prevProp, prevState){
        const secondCh = (this.state.firstVal * this.state.values[this.state.secCur]).toFixed(2)
        if(this.state.secVal !== secondCh){
            console.log(this.state.values)
            this.setState({secVal : secondCh})
        }
    }

    callApi(val){
        fetch("https://api.exchangeratesapi.io/latest?base=" + val)
        .then(res => res.json())
        .then(
            (result) => {
                this.setState({
                    values: result.rates,
                    firstCur: val
                });
            },
            (error) => {}
        )
    }

    handleChange(event){
        const target = event.target;
        const name = target.name;
        const value = target.value;
        if (name === "firstCur") {
            this.callApi(value)
        }
        else {
            this.setState({
                [name]: value
            });
        }
    }

    render(){
        const {firstCur, secCur, firstVal, secVal} = this.state
        const options = Object.keys(this.state.values).map(key => (
            <option value={key}>{ this.codeName[key] }</option>
        ))
        
        return(
            <form>
                <h2>Конвертер</h2>
                <div>
                    <input name="firstVal" value={firstVal} type="number" onChange={this.handleChange} />
                    <input type="number" value={secVal} disabled />
                </div>
                <div>
                    <select name="firstCur" value={firstCur} onChange={this.handleChange}>
                        { options }
                    </select>
                    <select name="secCur" value={secCur} onChange={this.handleChange}>
                        { options }
                    </select>
                </div>
            </form>
        )
    }
}

export default Converter