import React from 'react'
import { Redirect } from 'react-router-dom'
import firebase from '../FirebaseConfig'


class SignInForm extends React.Component{
    constructor(props){
        super(props);
        this.state = {
            login: "",
            pass: "",
            redirect: false
        }

        this.handleSubmit = this.handleSubmit.bind(this);
        this.handleChange = this.handleChange.bind(this);
    }

    handleChange(event){
        const target = event.target;
        const name = target.name;
        const value = target.value;
        this.setState({
            [name] : value
        });
    }

    handleSubmit(event){
        firebase.firestore().collection('auth').get().then((snapshot) => {
            snapshot.docs.forEach(doc => {
                if((this.state.login === doc.data().login) && (this.state.pass === doc.data().pass)){
                    this.setState({ redirect: true})
                    alert("You're logged in")
                    this.props.updateLogin(1)
                    return;
                }
            })
        })
        event.preventDefault();
    }

    render() {
        const {login, pass, redirect} = this.state;
        if (redirect === true)
            return <Redirect push to="/" />

        return(
            <form onSubmit={this.handleSubmit}>
                <input name="login" value={login} onChange={this.handleChange} type="text" required />
                <input name="pass" value={pass} onChange={this.handleChange} type="password" required />
            </form>
        );
    }
}

export default SignInForm;